1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[1]])).toEqual([]);
10	  });
11	  it("should return empty grid when two cells die from underpopulation", () => {
12	    expect(nextGeneration([[1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 live neighbors (survival)", () => {
15	    // Middle cell has 2 live neighbors (left and right), so it survives
16	    // Edge cells each have only 1 live neighbor, so they die
17	    expect(nextGeneration([[1, 1, 1]])).toEqual([[0, 1, 0]]);
18	  });
19	  it("should keep a live cell alive when it has 3 live neighbors (survival)", () => {
20	    // In a 2x2 grid of all live cells, each cell has exactly 3 live neighbors, so all survive
21	    expect(nextGeneration([[1, 1], [1, 1]])).toEqual([[1, 1], [1, 1]]);
22	  });
23	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
24	    // In a 2x2 fully live grid extended to 2x3, the middle cells have 5 live neighbors
25	    // [[1,1,1],[1,1,1]]: center cells (0,1) and (1,1) each have 5 neighbors -> die
26	    expect(nextGeneration([[1, 1, 1], [1, 1, 1]])).toEqual([[1, 0, 1], [1, 0, 1]]);
27	  });
28	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
29	    // Dead cell at (1,1) has 3 live neighbors: (0,0), (0,1), (1,0) -> comes alive
30	    // All three live cells each have exactly 2 live neighbors -> survive
31	    expect(nextGeneration([[1, 1], [1, 0]])).toEqual([[1, 1], [1, 1]]);
32	  });
33	  it.todo("should compute next generation for the block (still life)");
34	  it.todo("should compute next generation for the blinker (oscillator, first step)");
35	  it.todo("should compute next generation for the blinker (oscillator, second step)");
36	});
