1	type Grid = number[][];
2	
3	const countNeighbors = (grid: Grid, row: number, col: number): number => {
4	  let count = 0;
5	  const rows = grid.length;
6	  const cols = grid[0]?.length ?? 0;
7	  for (let r = row - 1; r <= row + 1; r++) {
8	    for (let c = col - 1; c <= col + 1; c++) {
9	      if (r === row && c === col) continue;
10	      if (r >= 0 && r < rows && c >= 0 && c < cols) {
11	        count += grid[r][c];
12	      }
13	    }
14	  }
15	  return count;
16	};
17	
18	export function nextGeneration(grid: Grid): Grid {
19	  if (grid.length === 0) return [];
20	  const rows = grid.length;
21	  const cols = grid[0].length;
22	  const next: Grid = [];
23	  for (let r = 0; r < rows; r++) {
24	    const nextRow: number[] = [];
25	    for (let c = 0; c < cols; c++) {
26	      const neighbors = countNeighbors(grid, r, c);
27	      const alive = grid[r][c] === 1;
28	      if ((alive && (neighbors === 2 || neighbors === 3)) || (!alive && neighbors === 3)) {
29	        nextRow.push(1);
30	      } else {
31	        nextRow.push(0);
32	      }
33	    }
34	    next.push(nextRow);
35	  }
36	  return next.filter(row => row.some(cell => cell === 1));
37	}
